noncompliant:
DateTime start = DateTime.Now;
// ... some operations
TimeSpan elapsed = DateTime.Now - start; // Noncompliant

compliant:
Stopwatch stopwatch = Stopwatch.StartNew();
// ... some operations
stopwatch.Stop();
TimeSpan elapsed = stopwatch.Elapsed; // Compliant

var timing = Stopwatch.StartNew();
// ... operations
timing.Stop();
var milliseconds = timing.ElapsedMilliseconds; // Compliant

DateTimeOffset start = DateTimeOffset.Now;
// ... operations
TimeSpan elapsed = DateTimeOffset.Now - start; // Compliant for wall-clock measurements
